using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient from DI
/// and creates a new instance per tool invocation.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Get a single item by its ID.")]
    public async Task<string> GetItem(
        [Description("Numeric ID of the item to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("Search for items by query string.")]
    public async Task<string> SearchItems(
        [Description("Search query to filter items")] string query,
        [Description("Maximum number of results (1-50, default 10)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync($"/items?q={Uri.EscapeDataString(query)}&limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Create a new item with a name and optional description.")]
    public async Task<string> CreateItem(
        [Description("Name of the item to create")] string name,
        [Description("Optional description for the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

